INSERT INTO sales_demo_app.sales_orders (order_id, customer_id, salesperson_id, order_date, status, total_value, expected_close_date, actual_close_date, lost_reason, metadata, win_reason, forecast_confidence, confidence_pct, inserted_at, qty, product_id) VALUES (469, 120, 2, '2026-02-18T00:00:00', 'won', '75703.04', NULL, '2026-02-21', NULL, NULL, 'Their BI dashboards (Tableau) were "too static." This tool allowed them to "interactively drill down" by asking follow-up questions to the data, which was a "wow" moment for the exec team.', NULL, NULL, '2026-02-21T18:12:17.048113', 1, 5);
INSERT INTO sales_demo_app.sales_orders (order_id, customer_id, salesperson_id, order_date, status, total_value, expected_close_date, actual_close_date, lost_reason, metadata, win_reason, forecast_confidence, confidence_pct, inserted_at, qty, product_id) VALUES (477, 132, 2, '2025-12-24T00:00:00', 'won', '68050.53', '2026-02-21', '2026-02-21', NULL, NULL, 'They had no central "feature store." Their teams were rebuilding the same features (e.g., "customer 30-day spend") over and over. Our built-in feature store eliminated this duplicate work.', NULL, NULL, '2026-02-21T18:12:17.050239', 1, 3);
