INSERT INTO sales_demo_app.sales_orders (order_id, customer_id, salesperson_id, order_date, status, total_value, expected_close_date, actual_close_date, lost_reason, metadata, win_reason, forecast_confidence, confidence_pct, inserted_at, qty, product_id) VALUES (482, 112, 2, '2026-01-06T00:00:00', 'won', '47012.65', NULL, '2026-02-21', NULL, NULL, 'They were "burned" by a public cloud provider''s sudden API price hike. They bought our Factory for predictable costs and to avoid vendor lock-in, giving them control over their AI strategy.', NULL, NULL, '2026-02-21T18:12:17.051478', 1, 1);
INSERT INTO sales_demo_app.sales_orders (order_id, customer_id, salesperson_id, order_date, status, total_value, expected_close_date, actual_close_date, lost_reason, metadata, win_reason, forecast_confidence, confidence_pct, inserted_at, qty, product_id) VALUES (494, 122, 1, '2026-02-04T00:00:00', 'won', '89118.26', NULL, '2026-02-21', NULL, NULL, 'The legal team built an agent to analyze their contract database, which was previously just a "digital filing cabinet." Now they can ask, "Show me all contracts with non-standard liability clauses."', NULL, NULL, '2026-02-21T18:12:17.054838', 1, 1);
INSERT INTO sales_demo_app.sales_orders (order_id, customer_id, salesperson_id, order_date, status, total_value, expected_close_date, actual_close_date, lost_reason, metadata, win_reason, forecast_confidence, confidence_pct, inserted_at, qty, product_id) VALUES (534, 288, 2, '2026-02-21T02:27:50', 'won', '652.89', '2026-02-21', '2026-02-21', NULL, '{"source": "crm", "priority": "medium"}'::jsonb, 'Frequent "too many connections" errors were causing application-level failures and impacting end-user experience.', 'green', 88, '2026-02-21T02:27:50', 1, 6011);
INSERT INTO sales_demo_app.sales_orders (order_id, customer_id, salesperson_id, order_date, status, total_value, expected_close_date, actual_close_date, lost_reason, metadata, win_reason, forecast_confidence, confidence_pct, inserted_at, qty, product_id) VALUES (541, 60, 1, '2026-02-21T00:54:44', 'won', '608.04', '2026-04-06', '2026-04-06', NULL, '{"source": "crm", "priority": "medium"}'::jsonb, 'They had no "data catalog." No one knew what data was available. Converge''s "AI-powered data catalog" automatically "crawled" their lake and "tagged" their data.', 'green', 77, '2026-02-21T00:54:44', 1, 6018);
INSERT INTO sales_demo_app.sales_orders (order_id, customer_id, salesperson_id, order_date, status, total_value, expected_close_date, actual_close_date, lost_reason, metadata, win_reason, forecast_confidence, confidence_pct, inserted_at, qty, product_id) VALUES (547, 7, 2, '2026-02-21T11:06:58', 'won', '469.56', '2026-02-21', '2026-02-21', NULL, '{"source": "crm", "priority": "medium"}'::jsonb, 'They needed to simulate 10,000 concurrent users for a load test but lacked the tools. The DevKit''s built-in benchmarking suite provided this capability.', 'green', 100, '2026-02-21T11:06:58', 1, 6015);
INSERT INTO sales_demo_app.sales_orders (order_id, customer_id, salesperson_id, order_date, status, total_value, expected_close_date, actual_close_date, lost_reason, metadata, win_reason, forecast_confidence, confidence_pct, inserted_at, qty, product_id) VALUES (550, 197, 2, '2026-02-21T05:45:03', 'won', '427.37', '2026-02-21', '2026-02-21', NULL, '{"source": "crm", "priority": "medium"}'::jsonb, 'They had 5 different data silos (Salesforce, Zendesk, Postgres, S3). The builder was able to connect to all 5, and they built a "Customer 360" agent that could answer questions by pulling data from all sources.', 'green', 93, '2026-02-21T05:45:03', 1, 1);
INSERT INTO sales_demo_app.sales_orders (order_id, customer_id, salesperson_id, order_date, status, total_value, expected_close_date, actual_close_date, lost_reason, metadata, win_reason, forecast_confidence, confidence_pct, inserted_at, qty, product_id) VALUES (566, 197, 1, '2026-02-21T07:34:39', 'lost', '816.95', '2026-02-21', '2026-02-21', 'The developers found the tool "overwhelming" and "built for DBAs"; they just wanted a simple query-check, not a complex profiler.**', '{"source": "crm", "priority": "medium"}'::jsonb, NULL, 'green', 82, '2026-02-21T07:34:39', 1, 6016);
