INSERT INTO sales_demo_app.sales_orders (order_id, customer_id, salesperson_id, order_date, status, total_value, expected_close_date, actual_close_date, lost_reason, metadata, win_reason, forecast_confidence, confidence_pct, inserted_at, qty, product_id) VALUES (580, 246, 1, '2026-02-21T15:33:56', 'won', '637.32', '2026-02-21', '2026-02-21', NULL, '{"source": "crm", "priority": "medium"}'::jsonb, 'Their team was constantly "reinventing the wheel." They bought this to access our library of best-practice guides and performance tuning "cookbooks."', 'red', 40, '2026-02-21T15:33:56', 1, 4);
