INSERT INTO sales_demo_app.sales_orders (order_id, customer_id, salesperson_id, order_date, status, total_value, expected_close_date, actual_close_date, lost_reason, metadata, win_reason, forecast_confidence, confidence_pct, inserted_at, qty, product_id) VALUES (686, 154, 1, '2026-02-21T04:50:59', 'won', '740.18', '2026-04-10', '2026-04-10', NULL, '{"source": "crm", "priority": "medium"}'::jsonb, 'They were "stuck in PoC hell." They had 10 small AI projects that never got to production. Our Factory was the "production path" to operationalize and scale these models.', 'green', 89, '2026-02-21T04:50:59', 1, 1);
