INSERT INTO sales_demo_app.sales_orders (order_id, customer_id, salesperson_id, order_date, status, total_value, expected_close_date, actual_close_date, lost_reason, metadata, win_reason, forecast_confidence, confidence_pct, inserted_at, qty, product_id) VALUES (713, 115, 2, '2026-02-21T18:05:51', 'won', '758.41', '2026-02-21', '2026-02-21', NULL, '{"source": "crm", "priority": "medium"}'::jsonb, 'They were using disk-level encryption, but their security team mandated database-level encryption to protect against privileged OS user attacks.', 'yellow', 48, '2026-02-21T18:05:51', 1, 6012);
INSERT INTO sales_demo_app.sales_orders (order_id, customer_id, salesperson_id, order_date, status, total_value, expected_close_date, actual_close_date, lost_reason, metadata, win_reason, forecast_confidence, confidence_pct, inserted_at, qty, product_id) VALUES (721, 60, 2, '2026-02-21T03:21:58', 'won', '809.60', '2026-02-21', '2026-02-21', NULL, '{"source": "crm", "priority": "medium"}'::jsonb, 'Customer is expanding into Europe and needs to prove GDPR compliance. They bought OmniConnect to log and prove all access to PII is legitimate.', 'green', 85, '2026-02-21T03:21:58', 1, 6011);
INSERT INTO sales_demo_app.sales_orders (order_id, customer_id, salesperson_id, order_date, status, total_value, expected_close_date, actual_close_date, lost_reason, metadata, win_reason, forecast_confidence, confidence_pct, inserted_at, qty, product_id) VALUES (722, 28, 1, '2026-02-21T23:13:58', 'lost', '591.02', '2026-02-21', '2026-02-21', 'Lost to AWS, as their developers preferred to just call the "AWS Bedrock" API from their existing code rather than "onboard" to our "Factory."**', '{"source": "crm", "priority": "medium"}'::jsonb, NULL, 'red', 17, '2026-02-21T23:13:58', 1, 6020);
INSERT INTO sales_demo_app.sales_orders (order_id, customer_id, salesperson_id, order_date, status, total_value, expected_close_date, actual_close_date, lost_reason, metadata, win_reason, forecast_confidence, confidence_pct, inserted_at, qty, product_id) VALUES (728, 28, 1, '2026-02-21T17:03:56', 'won', '486.83', '2026-02-21', '2026-02-21', NULL, '{"source": "crm", "priority": "medium"}'::jsonb, 'Their "citizen developer" program failed because other tools were still too complex. Our visual, drag-and-drop interface was the first one their "power users" in finance could successfully adopt.', 'green', 89, '2026-02-21T17:03:56', 1, 2);
INSERT INTO sales_demo_app.sales_orders (order_id, customer_id, salesperson_id, order_date, status, total_value, expected_close_date, actual_close_date, lost_reason, metadata, win_reason, forecast_confidence, confidence_pct, inserted_at, qty, product_id) VALUES (737, 65, 2, '2026-02-21T09:39:13', 'won', '902.63', '2026-02-21', '2026-02-21', NULL, '{"source": "crm", "priority": "medium"}'::jsonb, 'They ran out of database connections. Guardian''s "connection pool usage" trend report would have shown them they were approaching their limit for weeks.', 'yellow', 58, '2026-02-21T09:39:13', 1, 6012);
INSERT INTO sales_demo_app.sales_orders (order_id, customer_id, salesperson_id, order_date, status, total_value, expected_close_date, actual_close_date, lost_reason, metadata, win_reason, forecast_confidence, confidence_pct, inserted_at, qty, product_id) VALUES (742, 79, 1, '2026-02-21T09:15:03', 'won', '678.86', '2026-02-21', '2026-02-21', NULL, '{"source": "crm", "priority": "medium"}'::jsonb, 'When a QA test finished, they had no idea what the "load impact" was. Guardian provided a "post-test summary report" showing CPU, I/O, and query metrics for the duration of the test.', 'red', 13, '2026-02-21T09:15:03', 1, 6016);
INSERT INTO sales_demo_app.sales_orders (order_id, customer_id, salesperson_id, order_date, status, total_value, expected_close_date, actual_close_date, lost_reason, metadata, win_reason, forecast_confidence, confidence_pct, inserted_at, qty, product_id) VALUES (759, 59, 2, '2026-02-21T12:45:46', 'won', '635.69', '2026-02-21', '2026-02-21', NULL, '{"source": "crm", "priority": "medium"}'::jsonb, 'Their "fraud-detection" system was "batch-based" and would catch fraud "6 hours late." Converge''s "real-time" engine allowed them to "score" transactions *before* they were completed.', 'green', 87, '2026-02-21T12:45:46', 1, 6018);
INSERT INTO sales_demo_app.sales_orders (order_id, customer_id, salesperson_id, order_date, status, total_value, expected_close_date, actual_close_date, lost_reason, metadata, win_reason, forecast_confidence, confidence_pct, inserted_at, qty, product_id) VALUES (763, 29, 2, '2026-02-21T21:11:42', 'won', '88.65', '2026-02-21', '2026-02-21', NULL, '{"source": "crm", "priority": "medium"}'::jsonb, 'They were paying for Zapier, Workato, *and* internal scripts. Synapse was bought to consolidate all their business process automation onto one platform.', 'green', 84, '2026-02-21T21:11:42', 1, 6017);
INSERT INTO sales_demo_app.sales_orders (order_id, customer_id, salesperson_id, order_date, status, total_value, expected_close_date, actual_close_date, lost_reason, metadata, win_reason, forecast_confidence, confidence_pct, inserted_at, qty, product_id) VALUES (765, 198, 2, '2026-02-21T12:02:00', 'won', '919.66', '2026-02-21', '2026-02-21', NULL, '{"source": "crm", "priority": "medium"}'::jsonb, 'To get their cyber-insurance policy renewed, they were required to show they had specific database-level intrusion detection and prevention (IDP).', 'red', 28, '2026-02-21T12:02:00', 1, 6011);
INSERT INTO sales_demo_app.sales_orders (order_id, customer_id, salesperson_id, order_date, status, total_value, expected_close_date, actual_close_date, lost_reason, metadata, win_reason, forecast_confidence, confidence_pct, inserted_at, qty, product_id) VALUES (770, 116, 1, '2026-02-21T02:16:32', 'won', '103.99', '2026-02-21', '2026-02-21', NULL, '{"source": "crm", "priority": "medium"}'::jsonb, 'They had no way to "version control" their database schema alongside their application code. The DevKit''s Git integration solved this.', 'yellow', 64, '2026-02-21T02:16:32', 1, 3);
