INSERT INTO sales_demo_app.sales_orders (order_id, customer_id, salesperson_id, order_date, status, total_value, expected_close_date, actual_close_date, lost_reason, metadata, win_reason, forecast_confidence, confidence_pct, inserted_at, qty, product_id) VALUES (2358, 300, 2, '2026-02-21T05:46:02', 'lost', '224.16', '2026-04-10', '2026-04-10', 'Lost to 3rd-party support. A local IT consultancy offered them an 8x5 "support on a budget" contract for the open-source version that was 30% cheaper than our PillarDB Standard license.**', '{"source": "crm", "priority": "medium"}'::jsonb, NULL, 'green', 96, '2026-02-21T05:46:02', 1, 6013);
INSERT INTO sales_demo_app.sales_orders (order_id, customer_id, salesperson_id, order_date, status, total_value, expected_close_date, actual_close_date, lost_reason, metadata, win_reason, forecast_confidence, confidence_pct, inserted_at, qty, product_id) VALUES (2362, 128, 2, '2026-02-21T09:07:26', 'lost', '71.28', '2026-02-21', '2026-02-21', 'The governance rules were "too restrictive" and "slowed down" the data science team, who successfully lobbied to have the tool removed.**', '{"source": "crm", "priority": "medium"}'::jsonb, NULL, 'green', 87, '2026-02-21T09:07:26', 1, 6020);
INSERT INTO sales_demo_app.sales_orders (order_id, customer_id, salesperson_id, order_date, status, total_value, expected_close_date, actual_close_date, lost_reason, metadata, win_reason, forecast_confidence, confidence_pct, inserted_at, qty, product_id) VALUES (2394, 282, 1, '2026-02-21T07:27:02', 'lost', '810.09', '2026-02-21', '2026-02-21', 'Lost to cloud-native. The customer is migrating to Azure SQL Database, which has built-in, fully managed "Failover Groups" that cover their HA and DR needs. They did not want to pay for a third-party tool to replicate a feature their cloud provider gives them.**', '{"source": "crm", "priority": "medium"}'::jsonb, NULL, 'red', 29, '2026-02-21T07:27:02', 1, 4);
INSERT INTO sales_demo_app.sales_orders (order_id, customer_id, salesperson_id, order_date, status, total_value, expected_close_date, actual_close_date, lost_reason, metadata, win_reason, forecast_confidence, confidence_pct, inserted_at, qty, product_id) VALUES (2395, 234, 1, '2026-02-21T07:36:49', 'won', '38.91', '2026-02-21', '2026-02-21', NULL, '{"source": "crm", "priority": "medium"}'::jsonb, 'The sales team sold a new "AI-powered search" feature that didn''t exist. The dev team bought our Factory because its "semantic-search-API" was the fastest way to build the feature and meet their deadline.', 'red', 24, '2026-02-21T07:36:49', 1, 2);
INSERT INTO sales_demo_app.sales_orders (order_id, customer_id, salesperson_id, order_date, status, total_value, expected_close_date, actual_close_date, lost_reason, metadata, win_reason, forecast_confidence, confidence_pct, inserted_at, qty, product_id) VALUES (2396, 109, 1, '2026-02-21T14:18:46', 'won', '339.63', '2026-02-21', '2026-02-21', NULL, '{"source": "crm", "priority": "medium"}'::jsonb, 'They were paying for Zapier, Workato, *and* internal scripts. Synapse was bought to consolidate all their business process automation onto one platform.', 'yellow', 51, '2026-02-21T14:18:46', 1, 6017);
INSERT INTO sales_demo_app.sales_orders (order_id, customer_id, salesperson_id, order_date, status, total_value, expected_close_date, actual_close_date, lost_reason, metadata, win_reason, forecast_confidence, confidence_pct, inserted_at, qty, product_id) VALUES (2429, 102, 1, '2026-02-21T17:52:08', 'lost', '39.32', '2026-02-21', '2026-02-21', 'The QA team has zero budget for tools, and the developers see performance testing as "QA''s problem," so the purchase stalled.**', '{"source": "crm", "priority": "medium"}'::jsonb, NULL, 'red', 20, '2026-02-21T17:52:08', 1, 5);
INSERT INTO sales_demo_app.sales_orders (order_id, customer_id, salesperson_id, order_date, status, total_value, expected_close_date, actual_close_date, lost_reason, metadata, win_reason, forecast_confidence, confidence_pct, inserted_at, qty, product_id) VALUES (2436, 217, 2, '2026-02-21T07:38:43', 'lost', '791.63', '2026-02-21', '2026-02-21', 'The "need for speed" was subjective. The business users "felt" the app was slow, but the engineering team could not get budget approval for the expensive Enterprise upgrade, so the project was shelved.**', '{"source": "crm", "priority": "medium"}'::jsonb, NULL, 'green', 91, '2026-02-21T07:38:43', 1, 2);
