INSERT INTO sales_demo_app.sales_orders (order_id, customer_id, salesperson_id, order_date, status, total_value, expected_close_date, actual_close_date, lost_reason, metadata, win_reason, forecast_confidence, confidence_pct, inserted_at, qty, product_id) VALUES (4793, 593, 2, '2026-01-11T00:00:00', 'won', '5186.32', NULL, '2026-04-06', NULL, NULL, 'Their main concern was "model theft"—an attacker stealing their custom-trained, proprietary model. Our platform''s "model encryption at rest" and "VPC-only access controls" solved this.', NULL, NULL, '2026-02-21T18:37:43.777127', 1, 6020);
