INSERT INTO sales_demo_app.sales_orders (order_id, customer_id, salesperson_id, order_date, status, total_value, expected_close_date, actual_close_date, lost_reason, metadata, win_reason, forecast_confidence, confidence_pct, inserted_at, qty, product_id) VALUES (4813, 229, 2, '2026-02-21T14:25:18', 'won', '765.30', '2026-04-06', '2026-04-06', NULL, '{"source": "crm", "priority": "medium"}'::jsonb, 'They had 5 different teams building their own AI apps, creating "shadow AI" sprawl. Our Factory was bought to centralize and audit all AI development and deployment from a single-pane-of-glass.', 'red', 23, '2026-02-21T14:25:18', 1, 2);
INSERT INTO sales_demo_app.sales_orders (order_id, customer_id, salesperson_id, order_date, status, total_value, expected_close_date, actual_close_date, lost_reason, metadata, win_reason, forecast_confidence, confidence_pct, inserted_at, qty, product_id) VALUES (4834, 216, 1, '2026-02-21T06:49:45', 'lost', '556.14', '2026-04-10', '2026-04-10', 'The application team decided to solve the problem in their code. They are re-architecting their microservices to use a persistent, shared connection pool library (e.g., HikariCP) within the application tier, removing the need for an external proxy.**', '{"source": "crm", "priority": "medium"}'::jsonb, NULL, 'red', 40, '2026-02-21T06:49:45', 1, 6011);
