INSERT INTO sales_demo_app.sales_orders (order_id, customer_id, salesperson_id, order_date, status, total_value, expected_close_date, actual_close_date, lost_reason, metadata, win_reason, forecast_confidence, confidence_pct, inserted_at, qty, product_id) VALUES (11749, 675, 39, '2026-04-19T17:40:42', 'won', '688.56', '2026-04-19', '2026-04-19', NULL, '{"source": "crm", "priority": "medium"}'::jsonb, 'Their unit tests for the application code were good, but they had zero testing for their stored procedures. The DevKit''s "SQL unit testing" framework filled this gap.', 'green', 99, '2026-04-19T17:40:42', 1, 6015);
INSERT INTO sales_demo_app.sales_orders (order_id, customer_id, salesperson_id, order_date, status, total_value, expected_close_date, actual_close_date, lost_reason, metadata, win_reason, forecast_confidence, confidence_pct, inserted_at, qty, product_id) VALUES (11752, 134, 31, '2026-04-19T00:40:37', 'won', '641.22', '2026-04-19', '2026-04-19', NULL, '{"source": "crm", "priority": "medium"}'::jsonb, 'Their database was write-intensive, and the open-source version''s single-threaded replication was a bottleneck. Enterprise "parallel replication" solved this.', 'yellow', 44, '2026-04-19T00:40:37', 1, 6017);
INSERT INTO sales_demo_app.sales_orders (order_id, customer_id, salesperson_id, order_date, status, total_value, expected_close_date, actual_close_date, lost_reason, metadata, win_reason, forecast_confidence, confidence_pct, inserted_at, qty, product_id) VALUES (11756, 1208, 40, '2026-04-19T22:55:41', 'lost', '756.24', '2026-04-19', '2026-04-19', 'The SRE team preferred to build their own automation using their existing stack of Ansible, Terraform, and Python scripts.**', '{"source": "crm", "priority": "medium"}'::jsonb, NULL, 'yellow', 64, '2026-04-19T22:55:41', 1, 6017);
