INSERT INTO sales_demo_app.sales_orders (order_id, customer_id, salesperson_id, order_date, status, total_value, expected_close_date, actual_close_date, lost_reason, metadata, win_reason, forecast_confidence, confidence_pct, inserted_at, qty, product_id) VALUES (11996, 555, 31, '2026-04-19T10:12:40', 'won', '371.07', '2026-04-19', '2026-04-19', NULL, '{"source": "crm", "priority": "medium"}'::jsonb, 'Their serverless functions were overwhelming the database with short-lived connections. OmniConnect''s pooling was the only viable solution to make their architecture work.', 'yellow', 61, '2026-04-19T10:12:40', 1, 6011);
INSERT INTO sales_demo_app.sales_orders (order_id, customer_id, salesperson_id, order_date, status, total_value, expected_close_date, actual_close_date, lost_reason, metadata, win_reason, forecast_confidence, confidence_pct, inserted_at, qty, product_id) VALUES (12014, 387, 50, '2026-04-19T05:17:08', 'won', '1005.90', '2026-04-19', '2026-04-19', NULL, '{"source": "crm", "priority": "medium"}'::jsonb, 'An auditor "failed" them because they couldn''t explain *why* an AI model had denied a loan. Our Factory''s "model-lineage" and "explainability" features were the direct fix for this audit finding.', 'green', 90, '2026-04-19T05:17:08', 1, 5);
INSERT INTO sales_demo_app.sales_orders (order_id, customer_id, salesperson_id, order_date, status, total_value, expected_close_date, actual_close_date, lost_reason, metadata, win_reason, forecast_confidence, confidence_pct, inserted_at, qty, product_id) VALUES (12028, 2321, 20, '2026-04-19T01:11:50', 'won', '438.91', '2026-04-19', '2026-04-19', NULL, '{"source": "crm", "priority": "medium"}'::jsonb, 'The "fix" on the community forum was a complex workaround, not a real patch. They wanted the official, clean bugfix from the vendor.', 'yellow', 52, '2026-04-19T01:11:50', 1, 6013);
INSERT INTO sales_demo_app.sales_orders (order_id, customer_id, salesperson_id, order_date, status, total_value, expected_close_date, actual_close_date, lost_reason, metadata, win_reason, forecast_confidence, confidence_pct, inserted_at, qty, product_id) VALUES (12032, 504, 36, '2026-04-19T05:02:47', 'won', '982.69', '2026-04-19', '2026-04-19', NULL, '{"source": "crm", "priority": "medium"}'::jsonb, 'They were paying for Zapier, Workato, *and* internal scripts. Synapse was bought to consolidate all their business process automation onto one platform.', 'yellow', 54, '2026-04-19T05:02:47', 1, 6017);
INSERT INTO sales_demo_app.sales_orders (order_id, customer_id, salesperson_id, order_date, status, total_value, expected_close_date, actual_close_date, lost_reason, metadata, win_reason, forecast_confidence, confidence_pct, inserted_at, qty, product_id) VALUES (12040, 2322, 47, '2026-04-19T06:48:48', 'lost', '858.60', '2026-07-12', NULL, NULL, '{"source": "crm", "priority": "medium"}'::jsonb, NULL, 'green', 95, '2026-04-19T06:48:48', 1, 6019);
