INSERT INTO sales_demo_app.sales_notes (note_id, order_id, salesperson_id, note_text, note_type, created_at, use_case_mentioned, sentiment, product_name, use_case) VALUES (15254, 4488, 2, '## Call Summary: Miller Manufacturing Ltd

